20	            switch fields[2] {
21	            case "on":            screenEvents.append(ScreenEvent(kind: .on, time: date))
22	            case "off":           screenEvents.append(ScreenEvent(kind: .off, time: date))
23	            case "screensaverOn": screenEvents.append(ScreenEvent(kind: .screensaverOn, time: date))
24	            case "screensaverOff":screenEvents.append(ScreenEvent(kind: .screensaverOff, time: date))
25	            case "entry":         projectEntries.append(ProjectEntry(project: fields[4], time: date))
26	            default: break
27	            }
28	        }
29	
30	        screenEvents.sort { $0.time < $1.time }
31	        projectEntries.sort { $0.time < $1.time }
32	        return (screenEvents, projectEntries)
33	    }
34	
35	    private static func parseFields(_ line: String) -> [String] {
36	        var fields: [String] = []
37	        var current = ""
38	        var inQuotes = false
39	        var i = line.startIndex
40	        while i < line.endIndex {
41	            let c = line[i]
42	            if inQuotes {
43	                if c == "\"" {
44	                    let next = line.index(after: i)
45	                    if next < line.endIndex && line[next] == "\"" {
46	                        current.append("\"")
47	                        i = line.index(after: next)
48	                        continue
49	                    }
50	                    inQuotes = false
51	                } else {
52	                    current.append(c)
53	                }
54	            } else {
55	                if c == "\"" { inQuotes = true }
56	                else if c == "," { fields.append(current); current = "" }
57	                else { current.append(c) }
58	            }
59	            i = line.index(after: i)
60	        }
61	        fields.append(current)
62	        return fields
63	    }
64	}
